"use strict";(self.webpackChunkreact_restyle_components=self.webpackChunkreact_restyle_components||[]).push([[2707],{"./src/core-components/src/components/Table/Table.stories.tsx":(__unused_webpack_module,__webpack_exports__,__webpack_require__)=>{__webpack_require__.r(__webpack_exports__),__webpack_require__.d(__webpack_exports__,{BasicUsage:()=>BasicUsage,Documentation:()=>Documentation,ServerSidePagination:()=>ServerSidePagination,WithExportCharts:()=>WithExportCharts,WithExportExtraSheets:()=>WithExportExtraSheets,WithExportStyling:()=>WithExportStyling,WithFilters:()=>WithFilters,WithLoadingIndicator:()=>WithLoadingIndicator,WithPagination:()=>WithPagination,WithSelectionActions:()=>WithSelectionActions,WithSelectionHeaderActions:()=>WithSelectionHeaderActions,__namedExportsOrder:()=>__namedExportsOrder,default:()=>__WEBPACK_DEFAULT_EXPORT__});var react__WEBPACK_IMPORTED_MODULE_0__=__webpack_require__("./node_modules/react/index.js");const CodeExample=({title,code,description})=>react__WEBPACK_IMPORTED_MODULE_0__.createElement("div",{style:{padding:"20px"}},react__WEBPACK_IMPORTED_MODULE_0__.createElement("h2",{style:{marginTop:0}},title),description&&react__WEBPACK_IMPORTED_MODULE_0__.createElement("div",{style:{marginBottom:"16px",color:"#666"}},description),react__WEBPACK_IMPORTED_MODULE_0__.createElement("pre",{style:{background:"#f5f5f5",padding:"16px",borderRadius:"8px",overflow:"auto",fontSize:"14px",lineHeight:"1.5"}},react__WEBPACK_IMPORTED_MODULE_0__.createElement("code",null,code))),__WEBPACK_DEFAULT_EXPORT__={title:"Components/Table",tags:["autodocs"],parameters:{componentSubtitle:"import { Table } from 'react-restyle-components'",docs:{description:{component:"\n# Table Component\n\nA comprehensive data table component with sorting, filtering, pagination, row selection, cell editing, Excel export with embedded charts, and more.\n\n## Features\n- 🔄 Sorting (single/multi column)\n- 🔍 Column filters (text, number, date, select)\n- 🔎 Global search\n- 📄 Pagination (client/server-side)\n- ✅ Row selection (single, multiple, checkbox)\n- ✏️ Inline cell editing\n- 📊 Excel export with embedded bar / line / pie / doughnut charts\n- 📋 Multi-sheet Excel export (extra sheets with own data + charts)\n- 📝 Summary rows (totals, averages) appended at the bottom of exported sheet\n- 🎨 Export-time header styling (background color, font color, bold, size)\n- 👁️ Column visibility toggle\n- 📱 Responsive design\n- ♿ Full accessibility support\n- 🎯 Dynamic selection actions (toolbar + header)\n- ⏳ Top-right loading indicator (`isLoading`)\n\n## Basic Usage\n\n```tsx\nimport { Table, TableColumn } from 'react-restyle-components';\n\ninterface User {\n  _id: string;\n  name: string;\n  email: string;\n  age: number;\n}\n\nconst columns: TableColumn<User>[] = [\n  { dataField: 'name', text: 'Name', sort: true },\n  { dataField: 'email', text: 'Email', filter: true },\n  { dataField: 'age', text: 'Age', sort: true, filter: true },\n];\n\nconst data: User[] = [\n  { _id: '1', name: 'John Doe', email: 'john@example.com', age: 30 },\n  { _id: '2', name: 'Jane Smith', email: 'jane@example.com', age: 25 },\n];\n\n<Table \n  id=\"my-table\" \n  data={data} \n  columns={columns}\n  pagination\n  searchable\n/>\n```\n\n## Row Selection with Dynamic Actions\n\n```tsx\nimport { Table } from 'react-restyle-components';\nimport { useState } from 'react';\n\nfunction MyTable() {\n  const [selectedRows, setSelectedRows] = useState<User[]>([]);\n\n  return (\n    <Table\n      id=\"my-table\"\n      data={data}\n      columns={columns}\n      isSelectRow\n      onSelectedRow={setSelectedRows}\n      isSelectSort\n      onSelectSort={(selectedRows, keys) => {\n        console.log('Move to top:', selectedRows);\n      }}\n      selectionActions={[\n        {\n          nameIcon: 'FaWhatsapp',\n          propsIcon: { size: '24', color: '#fff' },\n          onClick: (selectedRows, keys) => console.log('WhatsApp', selectedRows),\n          tooltip: 'Send via WhatsApp',\n        },\n        {\n          nameIcon: 'FaTrash',\n          propsIcon: { size: '24', color: '#ff0000' },\n          onClick: (selectedRows, keys) => console.log('Delete', selectedRows),\n          tooltip: 'Delete selected',\n        },\n      ]}\n    />\n  );\n}\n```\n\n## Server-Side Pagination\n\n```tsx\n<Table\n  id=\"server-table\"\n  data={currentPageData}\n  columns={columns}\n  pagination\n  remote\n  totalSize={totalRecords}\n  onPageSizeChange={async (page, size) => {\n    const response = await fetchData(page, size);\n    setData(response.data);\n    setTotal(response.total);\n  }}\n/>\n```\n\n## Column Filters\n\n```tsx\nimport { TextFilter, NumberFilter, SelectFilter, DateFilter } from './filters';\n\nconst columns: TableColumn<User>[] = [\n  {\n    dataField: 'name',\n    text: 'Name',\n    filter: TextFilter({ placeholder: 'Search name...', delay: 300 }),\n  },\n  {\n    dataField: 'age',\n    text: 'Age',\n    filter: NumberFilter({ placeholder: 'Enter age...', defaultComparator: '>=' }),\n  },\n  {\n    dataField: 'status',\n    text: 'Status',\n    filter: SelectFilter({\n      placeholder: 'All statuses',\n      options: [\n        { value: 'active', label: 'Active' },\n        { value: 'inactive', label: 'Inactive' },\n      ],\n    }),\n  },\n  {\n    dataField: 'createdAt',\n    text: 'Created Date',\n    filter: DateFilter({ defaultRangeMode: true }),\n  },\n];\n\n<Table id=\"filtered-table\" data={data} columns={columns} filterable />\n```\n\n## Cell Editing\n\n```tsx\nconst columns: TableColumn<User>[] = [\n  {\n    dataField: 'name',\n    text: 'Name',\n    editable: true,\n    onCellEdit: (newValue, row, rowIndex, column) => {\n      console.log('Cell edited:', { newValue, row });\n    },\n  },\n];\n\n<Table\n  id=\"editable-table\"\n  data={data}\n  columns={columns}\n  editMode=\"dblclick\"\n  showEditIcon\n/>\n```\n\n## Excel Export with Charts\n\nEmbed bar, line, pie, or doughnut charts directly into the exported Excel file.\nCharts are rendered via the browser Canvas 2D API — no extra dependencies needed.\n\n```tsx\n<Table\n  id=\"chart-export-table\"\n  data={data}\n  columns={columns}\n  exportable\n  exportFormat=\"excel\"\n  exportFileName=\"sales_report\"\n  exportSheetName=\"Sales\"\n  exportHeaderStyle={{\n    backgroundColor: '#1e40af', // header background (default: #6b7280 gray)\n    color: '#ffffff',            // header text color (default: #ffffff white)\n    bold: true,\n    fontSize: 12,\n  }}\n  exportCharts={[\n    {\n      type: 'bar',            // 'bar' | 'line' | 'pie' | 'doughnut'\n      title: 'Monthly Revenue',\n      labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],\n      datasets: [\n        {\n          label: 'Revenue',\n          values: [12000, 19000, 15000, 22000, 18000, 25000],\n          color: '#3b82f6',\n        },\n        {\n          label: 'Expenses',\n          values: [8000, 11000, 9000, 14000, 12000, 16000],\n          color: '#ef4444',\n        },\n      ],\n      width: 700,    // canvas px (default: 600)\n      height: 400,   // canvas px (default: 350)\n      rowOffset: 2,  // gap rows below data (default: 2)\n      colOffset: 0,  // column anchor (default: 0)\n      colSpan: 10,   // Excel columns wide (default: 8)\n      rowSpan: 22,   // Excel rows tall (default: 20)\n    },\n    {\n      type: 'pie',\n      title: 'Revenue by Region',\n      labels: ['North', 'South', 'East', 'West'],\n      datasets: [\n        {\n          label: 'Region',\n          values: [30, 25, 20, 25],\n          color: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'],\n        },\n      ],\n    },\n  ]}\n/>\n```\n\n## Export Summary Rows\n\nAppend totals, averages, or any aggregated rows at the bottom of the exported sheet.\n\n```tsx\n<Table\n  id=\"summary-export-table\"\n  data={data}\n  columns={columns}\n  exportable\n  exportFormat=\"excel\"\n  exportSummaryRows={[\n    {\n      label: 'Total',\n      values: { revenue: 111000, expenses: 70000 },\n      style: { fontWeight: 'bold', backgroundColor: '#f3f4f6' },\n    },\n    {\n      label: 'Average',\n      values: { revenue: 18500, expenses: 11667 },\n      style: { fontStyle: 'italic' },\n    },\n  ]}\n/>\n```\n\n## Multi-Sheet Excel Export\n\nAdd extra worksheets to the same Excel file — each with its own data, columns, header style, summary rows, and charts.\n\n```tsx\n<Table\n  id=\"multi-sheet-table\"\n  data={mainData}\n  columns={mainColumns}\n  exportable\n  exportFormat=\"excel\"\n  exportSheetName=\"Overview\"\n  exportExtraSheets={[\n    {\n      name: 'Details',\n      data: detailData,\n      columns: [\n        { dataField: 'id', text: 'ID' },\n        { dataField: 'product', text: 'Product' },\n        { dataField: 'qty', text: 'Qty' },\n        {\n          dataField: 'amount',\n          text: 'Amount',\n          csvFormatter: (val) => `$${val.toFixed(2)}`,\n        },\n      ],\n      headerStyle: {\n        backgroundColor: '#065f46',\n        color: '#ffffff',\n        bold: true,\n        fontSize: 11,\n      },\n      summaryRows: [\n        { label: 'Total', values: { qty: 450, amount: 98200 } },\n      ],\n      charts: [\n        {\n          type: 'line',\n          title: 'Quantity Trend',\n          labels: ['Q1', 'Q2', 'Q3', 'Q4'],\n          datasets: [{ label: 'Qty', values: [100, 120, 110, 120], color: '#3b82f6' }],\n        },\n      ],\n    },\n    {\n      name: 'Summary',\n      data: summaryData,\n      columns: [\n        { dataField: 'region', text: 'Region' },\n        { dataField: 'total', text: 'Total' },\n      ],\n      headerStyle: { backgroundColor: '#7c3aed', color: '#ffffff' },\n      charts: [\n        {\n          type: 'doughnut',\n          title: 'Sales by Region',\n          labels: ['North', 'South', 'East', 'West'],\n          datasets: [\n            {\n              label: 'Sales',\n              values: [30, 25, 20, 25],\n              color: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'],\n            },\n          ],\n        },\n      ],\n    },\n  ]}\n/>\n```\n\n## Props Reference\n\n### Core Props\n- `id`: Unique table identifier (required)\n- `data`: Array of data objects (required)\n- `columns`: Array of column definitions (required)\n- `keyField`: Field name for unique row identification (default: `'_id'`)\n\n### Pagination\n- `pagination`: Enable pagination (default: true)\n- `remote`: Server-side mode (default: true)\n- `totalSize`: Total records for server-side pagination\n- `onPageSizeChange`: Callback for page/size changes\n- Quick jumper: Type page number in \"Go to\" input and click Go to jump\n\n### Selection\n- `isSelectRow`: Enable row selection with checkboxes\n- `isSelectSort`: Show \"move selected to top\" button\n- `onSelectSort`: Callback when select-sort is clicked\n- `selectionActions`: Array of custom action icons/buttons (pagination area)\n- `selectionHeaderActions`: Array of actions OR single React component (header toolbar)\n- `onSelectedRow`: Callback when rows are selected\n\n### Loading\n- `loading`: Full overlay loading state\n- `isLoading`: Top-right loading spinner (non-blocking)\n\n### Filtering & Search\n- `filterable`: Enable column filters\n- `searchable`: Enable global search\n- `searchPlaceholder`: Search input placeholder\n\n### Sorting\n- `sort`: Controlled sort state\n- `defaultSort`: Default sort configuration\n- `multiSort`: Enable multi-column sorting\n\n### Export\n| Prop | Type | Default | Description |\n|---|---|---|---|\n| `exportable` | `boolean` | `true` | Show export button |\n| `exportFileName` | `string` | `'table_export'` | Downloaded file name |\n| `exportFormat` | `'excel' \\| 'csv'` | `'excel'` | Export file format |\n| `exportSheetName` | `string` | `'Sheet1'` | Main sheet tab name |\n| `exportHeaderStyle` | `object` | gray bg / white text | Excel header row style |\n| `exportHeaderStyle.backgroundColor` | `string` | `'#6b7280'` | Header background color (hex) |\n| `exportHeaderStyle.color` | `string` | `'#ffffff'` | Header text color (hex) |\n| `exportHeaderStyle.bold` | `boolean` | `true` | Bold header text |\n| `exportHeaderStyle.fontSize` | `number` | `12` | Header font size |\n| `exportSummaryRows` | `ExportSummaryRow[]` | — | Aggregated rows at the bottom of the main sheet |\n| `exportExtraSheets` | `ExportExtraSheet[]` | — | Additional worksheets in the same Excel file |\n| `exportCharts` | `ExportChart[]` | — | Charts embedded in the main sheet |\n\n### ExportChart Properties\n| Prop | Type | Default | Description |\n|---|---|---|---|\n| `type` | `'bar' \\| 'line' \\| 'pie' \\| 'doughnut'` | — | Chart type (required) |\n| `title` | `string` | — | Title drawn above the chart |\n| `labels` | `string[]` | — | X-axis / slice labels (required) |\n| `datasets` | `ExportChartDataset[]` | — | One or more data series (required) |\n| `width` | `number` | `600` | Canvas render width (px) |\n| `height` | `number` | `350` | Canvas render height (px) |\n| `rowOffset` | `number` | `2` | Gap rows below data table |\n| `colOffset` | `number` | `0` | Column anchor (0-indexed) |\n| `colSpan` | `number` | `8` | Excel columns the chart spans |\n| `rowSpan` | `number` | `20` | Excel rows the chart spans |\n\n### ExportChartDataset Properties\n| Prop | Type | Description |\n|---|---|---|\n| `label` | `string` | Legend label |\n| `values` | `number[]` | Numeric values (one per label) |\n| `color` | `string \\| string[]` | Fill color — single hex or per-bar/slice array |\n| `backgroundColor` | `string \\| string[]` | Alias for `color` |\n\n## Selection Actions API\n\n`selectionActions` can be a **static array** OR a **function** that receives selectedRows and returns an array.\n\n```tsx\nselectionActions={[\n  {\n    nameIcon: 'FaTrash',\n    propsIcon: { size: '24', color: '#fff' },\n    onClick: (selectedRows, keys) => console.log('Delete', selectedRows),\n    tooltip: 'Delete selected',\n  },\n]}\n\n// Or as a function\nselectionActions={(selectedRows) => [\n  {\n    nameIcon: selectedRows.length > 5 ? 'FaExclamation' : 'FaTrash',\n    propsIcon: { size: '24', color: '#fff' },\n    onClick: (rows) => console.log('Delete', rows),\n    tooltip: `Delete ${selectedRows.length} rows`,\n  },\n]}\n```\n\n### Action Item Properties\n```tsx\n{\n  nameIcon: string;        // Icon name from react-icons (e.g., 'FaWhatsapp')\n  propsIcon?: {            // Props passed to Icon component\n    size?: string | number;\n    color?: string;\n    [key: string]: any;\n  };\n  onClick: (selectedRows?: T[], selectedKeys?: string[]) => void;\n  tooltip?: string;        // Tooltip text on hover\n  disabled?: boolean;      // Disable the action\n  className?: string;      // Custom CSS class\n}\n```\n\n## Selection Header Actions API\n\n`selectionHeaderActions` shows actions in the header toolbar (after Show/Hide Columns). Accepts **array** of action items OR **single React component**:\n\n```tsx\nselectionHeaderActions={[\n  {\n    nameIcon: 'FaTrash',\n    propsIcon: { size: 18, color: '#ef4444' },\n    onClick: (selectedRows, keys) => console.log('Delete', selectedRows),\n    tooltip: 'Delete selected',\n  },\n  {\n    customComponent: <button onClick={() => {}}>Custom</button>,\n    tooltip: 'Custom action',\n  },\n]}\n\n// Or single component\nselectionHeaderActions={<button>My Action</button>}\n```\n\n## Loading States\n\n- `loading`: Full overlay with spinner (blocks interaction)\n- `isLoading`: Small spinner at top-right corner (non-blocking)\n\n```tsx\n<Table id=\"loading-table\" data={data} columns={columns} isLoading={isFetching} />\n```\n\n## Examples\n\n### Basic Table\n```tsx\n<Table id=\"basic-table\" data={data} columns={columns} />\n```\n\n### With Pagination\n```tsx\n<Table id=\"paginated-table\" data={data} columns={columns} pagination />\n```\n\n### With Row Selection\n```tsx\n<Table\n  id=\"selectable-table\"\n  data={data}\n  columns={columns}\n  isSelectRow\n  onSelectedRow={(rows) => console.log('Selected:', rows)}\n/>\n```\n\n### With Filters\n```tsx\n<Table id=\"filtered-table\" data={data} columns={columns} filterable searchable />\n```\n\n### Full Featured\n```tsx\n<Table\n  id=\"full-table\"\n  data={data}\n  columns={columns}\n  pagination\n  filterable\n  searchable\n  isSelectRow\n  isSelectSort\n  selectionActions={[...]}\n  selectionHeaderActions={[...]}\n  exportable\n  exportFormat=\"excel\"\n  exportSheetName=\"Report\"\n  exportHeaderStyle={{ backgroundColor: '#1e40af', color: '#ffffff' }}\n  exportCharts={[{ type: 'bar', title: 'Sales', labels: [...], datasets: [...] }]}\n  exportSummaryRows={[{ label: 'Total', values: { revenue: 111000 } }]}\n  exportExtraSheets={[{ name: 'Details', data: [...], columns: [...] }]}\n  columnToggle\n  striped\n  hover\n  stickyHeader\n/>\n```\n        "}},layout:"padded"}},Documentation={name:"Documentation",parameters:{docs:{description:{story:"See the main documentation above for usage examples and API reference."}}},render:()=>null},BasicUsage={name:"Basic Usage",parameters:{docs:{description:{story:"\n## Basic Table Usage\n\nThe simplest way to use the Table component.\n\n### Required Props\n- `id`: Unique identifier for the table\n- `data`: Array of data objects\n- `columns`: Array of column definitions\n\n### Optional Props\n- `pagination`: Enable pagination (default: true)\n- `searchable`: Enable global search (default: true)\n- `filterable`: Enable column filters (default: false)\n- `exportable`: Show export button (default: true)\n- `exportFormat`: `'excel'` (default) or `'csv'`\n- `exportHeaderStyle`: Export-time header color/font — see **Export — Header Style** story\n- `exportCharts`: Embed bar/line/pie/doughnut charts in the Excel file — see **Export — Embedded Charts** story\n- `exportExtraSheets`: Add extra worksheets — see **Export — Extra Sheets** story\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Basic Table Usage",code:"import { Table, TableColumn } from 'react-restyle-components';\n\ninterface User {\n  _id: string;\n  name: string;\n  email: string;\n  age: number;\n}\n\nconst columns: TableColumn<User>[] = [\n  { dataField: 'name', text: 'Name', sort: true },\n  { dataField: 'email', text: 'Email', filter: true },\n  { dataField: 'age', text: 'Age', sort: true, filter: true },\n];\n\nconst data: User[] = [\n  { _id: '1', name: 'John Doe', email: 'john@example.com', age: 30 },\n  { _id: '2', name: 'Jane Smith', email: 'jane@example.com', age: 25 },\n];\n\n<Table \n  id=\"basic-table\" \n  data={data} \n  columns={columns}\n/>",description:"The simplest way to use the Table component with required props."})},WithSelectionActions={name:"With Selection Actions",parameters:{docs:{description:{story:'\n## Table with Selection Actions\n\nEnable row selection and add custom action buttons/icons.\n\n### Key Features\n- `isSelectRow`: Enables checkbox selection\n- `isSelectSort`: Shows "move selected to top" button\n- `selectionActions`: Array of custom action icons\n- Each action receives `selectedRows` and `selectedKeys` in onClick handler\n        '}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Table with Selection Actions",code:"import { Table } from 'react-restyle-components';\nimport { useState } from 'react';\n\nfunction MyTable() {\n  const [selectedRows, setSelectedRows] = useState<User[]>([]);\n\n  return (\n    <Table\n      id=\"table-with-actions\"\n      data={data}\n      columns={columns}\n      // Enable row selection\n      isSelectRow\n      onSelectedRow={setSelectedRows}\n      // Built-in select-sort feature (move selected to top)\n      isSelectSort\n      onSelectSort={(selectedRows, keys) => {\n        console.log('Move to top:', selectedRows);\n      }}\n      // Custom dynamic action buttons/icons\n      selectionActions={[\n        {\n          nameIcon: 'FaWhatsapp',\n          propsIcon: { size: '24', color: '#fff' },\n          onClick: (selectedRows, keys) => {\n            console.log('WhatsApp action', selectedRows);\n          },\n          tooltip: 'Send via WhatsApp',\n        },\n        {\n          nameIcon: 'FaTrash',\n          propsIcon: { size: '24', color: '#ff0000' },\n          onClick: (selectedRows, keys) => {\n            console.log('Delete action', selectedRows);\n          },\n          tooltip: 'Delete selected',\n        },\n      ]}\n    />\n  );\n}",description:"Enable row selection with custom action buttons/icons."})},WithPagination={name:"With Pagination",parameters:{docs:{description:{story:'\n## Table with Pagination\n\nEnable pagination with default settings.\n\n### Pagination Features\n- Default page size: 10\n- Page size changer: Shows dropdown to change items per page\n- Quick jumper: Type page number in input and click Go to jump (e.g., type 2 → Go → page 2 active)\n- Shows total count: "Showing 1-10 of 50"\n        '}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Table with Pagination",code:'<Table\n  id="paginated-table"\n  data={data}\n  columns={columns}\n  pagination\n/>',description:"Enable pagination with default settings. Quick jumper: type page number and click Go to jump."})},WithFilters={name:"With Filters",parameters:{docs:{description:{story:"\n## Table with Filters\n\nEnable column filters and global search.\n\n### Filter Types\n- **Text Filter**: For string columns\n- **Number Filter**: For numeric columns with comparators (=, !=, >, >=, <, <=)\n- **Select Filter**: For columns with predefined options\n- **Date Filter**: For date columns with range support\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Table with Filters",code:'<Table\n  id="filtered-table"\n  data={data}\n  columns={columns}\n  filterable\n  searchable\n  searchPlaceholder="Search all columns..."\n/>',description:"Enable column filters and global search functionality."})},ServerSidePagination={name:"Server-Side Pagination",parameters:{docs:{description:{story:"\n## Server-Side Pagination\n\nFor large datasets, use server-side pagination.\n\n### Key Props\n- `remote={true}`: Enables server-side mode (default)\n- `totalSize`: Total number of records on server\n- `onPageSizeChange`: Callback receives `(page, size)` - page is 1-indexed\n- `loading`: Full overlay loading (blocks interaction)\n- `isLoading`: Top-right spinner (non-blocking, table remains visible)\n\n### Auto-Detection\nIf `totalSize <= data.length`, automatically switches to client-side mode.\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Server-Side Pagination",code:"import { useState, useEffect } from 'react';\n\nfunction ServerTable() {\n  const [data, setData] = useState([]);\n  const [total, setTotal] = useState(0);\n  const [isLoading, setIsLoading] = useState(false);\n\n  const fetchData = async (page: number, size: number) => {\n    setIsLoading(true);\n    try {\n      const response = await fetch(`/api/users?page=${page}&size=${size}`);\n      const result = await response.json();\n      setData(result.data);\n      setTotal(result.total);\n    } finally {\n      setIsLoading(false);\n    }\n  };\n\n  useEffect(() => {\n    fetchData(1, 10); // Initial load\n  }, []);\n\n  return (\n    <Table\n      id=\"server-table\"\n      data={data}\n      columns={columns}\n      isLoading={isLoading}\n      pagination\n      remote\n      totalSize={total}\n      onPageSizeChange={fetchData}\n    />\n  );\n}",description:"For large datasets, fetch data from server. Use isLoading for top-right spinner or loading for full overlay."})},WithSelectionHeaderActions={name:"With Selection Header Actions",parameters:{docs:{description:{story:"\n## Table with Selection Header Actions\n\nActions in the header toolbar (after Show/Hide Columns). Supports icon name or custom component.\n\n### Key Features\n- `selectionHeaderActions`: Array of actions OR single React component\n- Always visible (positioned after FilterIcon)\n- `nameIcon`: Icon from react-icons (e.g., 'FaTrash')\n- `customComponent`: Custom React element for fully custom UI\n- `onClick`: Receives selectedRows and selectedKeys\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Table with Selection Header Actions",code:"// Array of actions (positioned after FilterIcon)\n<Table\n  id=\"header-actions-table\"\n  data={data}\n  columns={columns}\n  selectionHeaderActions={[\n    {\n      nameIcon: 'FaTrash',\n      propsIcon: { size: 18, color: '#ef4444' },\n      onClick: (rows, keys) => console.log('Delete', rows),\n      tooltip: 'Delete selected',\n    },\n    {\n      customComponent: <button>Custom</button>,\n      tooltip: 'Custom action',\n    },\n  ]}\n/>\n\n// Or single component\n<Table\n  id=\"header-actions-table\"\n  data={data}\n  columns={columns}\n  selectionHeaderActions={<button onClick={...}>My Action</button>}\n/>",description:"Header toolbar actions after Show/Hide Columns. Accepts array or single React component."})},WithLoadingIndicator={name:"With Loading Indicator",parameters:{docs:{description:{story:"\n## Table with Top-Right Loading Indicator\n\n`isLoading` shows a small LoadingAnimateSpin at the top-right corner (non-blocking).\n\n### Loading Props\n- `loading`: Full overlay (blocks interaction)\n- `isLoading`: Top-right spinner (table remains visible)\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Table with Loading Indicator",code:'// Top-right spinner (non-blocking)\n<Table\n  id="loading-table"\n  data={data}\n  columns={columns}\n  isLoading={isFetching}\n/>\n\n// Full overlay (blocks interaction)\n<Table\n  id="loading-table"\n  data={data}\n  columns={columns}\n  loading={loading}\n/>',description:"isLoading: top-right spinner. loading: full overlay."})},WithExportStyling={name:"Export — Header Style & Sheet Name",parameters:{docs:{description:{story:"\n## Export-Time Header Styling\n\nUse `exportHeaderStyle` to control the Excel header row appearance at export time.\nThese props are **independent of runtime table styles** and only affect the exported file.\n\n### Default behaviour (no props needed)\n- Background: `#6b7280` (gray)\n- Text color: `#ffffff` (white)\n- Bold: `true`, Font size: `12`\n\n### Props\n| Prop | Type | Default |\n|---|---|---|\n| `exportFormat` | `'excel' \\| 'csv'` | `'excel'` |\n| `exportSheetName` | `string` | `'Sheet1'` |\n| `exportHeaderStyle.backgroundColor` | `string` | `'#6b7280'` |\n| `exportHeaderStyle.color` | `string` | `'#ffffff'` |\n| `exportHeaderStyle.bold` | `boolean` | `true` |\n| `exportHeaderStyle.fontSize` | `number` | `12` |\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Export — Header Style & Sheet Name",code:'// Default: gray header (#6b7280) + white text — no extra props needed\n<Table\n  id="export-default"\n  data={data}\n  columns={columns}\n  exportable\n  exportFormat="excel"\n/>\n\n// Custom header style\n<Table\n  id="export-styled"\n  data={data}\n  columns={columns}\n  exportable\n  exportFormat="excel"\n  exportFileName="sales_report"\n  exportSheetName="Sales Data"\n  exportHeaderStyle={{\n    backgroundColor: \'#1e40af\', // dark blue\n    color: \'#ffffff\',\n    bold: true,\n    fontSize: 13,\n  }}\n/>\n\n// Green header\n<Table\n  id="export-green"\n  data={data}\n  columns={columns}\n  exportable\n  exportFormat="excel"\n  exportHeaderStyle={{\n    backgroundColor: \'#065f46\',\n    color: \'#a7f3d0\',\n    fontSize: 11,\n  }}\n/>',description:"exportHeaderStyle controls the Excel header independently of the visible table styles."})},WithExportCharts={name:"Export — Embedded Charts",parameters:{docs:{description:{story:"\n## Embedding Charts in Exported Excel\n\nUse `exportCharts` to embed one or more charts directly into the exported Excel sheet.\nCharts are rendered via the **browser Canvas 2D API** — no extra dependencies required.\n\n### Supported Chart Types\n- `'bar'` — vertical bar chart\n- `'line'` — line chart\n- `'pie'` — pie chart\n- `'doughnut'` — doughnut chart\n\n### Chart Positioning\nCharts are placed **below the data table** in the same sheet.\nControl placement with `rowOffset`, `colOffset`, `colSpan`, `rowSpan`.\n\n### Multiple datasets\nA single chart can carry multiple series (stacked bars, multi-line, etc.).\nFor pie / doughnut charts pass a `color` array — one colour per slice.\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Export — Embedded Charts",code:"<Table\n  id=\"chart-export-table\"\n  data={data}\n  columns={columns}\n  exportable\n  exportFormat=\"excel\"\n  exportFileName=\"sales_report\"\n  exportSheetName=\"Sales\"\n  exportHeaderStyle={{ backgroundColor: '#1e40af', color: '#ffffff' }}\n  exportCharts={[\n    // Bar chart — multi-series\n    {\n      type: 'bar',\n      title: 'Monthly Revenue vs Expenses',\n      labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],\n      datasets: [\n        {\n          label: 'Revenue',\n          values: [12000, 19000, 15000, 22000, 18000, 25000],\n          color: '#3b82f6',\n        },\n        {\n          label: 'Expenses',\n          values: [8000, 11000, 9000, 14000, 12000, 16000],\n          color: '#ef4444',\n        },\n      ],\n      width: 700,\n      height: 400,\n      rowOffset: 2,   // rows gap below data table\n      colOffset: 0,   // anchor column (0-indexed)\n      colSpan: 10,    // how many Excel columns wide\n      rowSpan: 22,    // how many Excel rows tall\n    },\n    // Line chart\n    {\n      type: 'line',\n      title: 'Revenue Trend',\n      labels: ['Q1', 'Q2', 'Q3', 'Q4'],\n      datasets: [\n        {\n          label: 'This Year',\n          values: [45000, 56000, 53000, 67000],\n          color: '#10b981',\n        },\n        {\n          label: 'Last Year',\n          values: [38000, 44000, 47000, 59000],\n          color: '#6b7280',\n        },\n      ],\n      colOffset: 11,  // place to the right of the bar chart\n    },\n    // Pie chart — per-slice colors\n    {\n      type: 'pie',\n      title: 'Revenue by Region',\n      labels: ['North', 'South', 'East', 'West'],\n      datasets: [\n        {\n          label: 'Region',\n          values: [30, 25, 20, 25],\n          color: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'],\n        },\n      ],\n    },\n    // Doughnut chart\n    {\n      type: 'doughnut',\n      title: 'Product Mix',\n      labels: ['Product A', 'Product B', 'Product C'],\n      datasets: [\n        {\n          label: 'Mix',\n          values: [40, 35, 25],\n          color: ['#7c3aed', '#db2777', '#0891b2'],\n        },\n      ],\n    },\n  ]}\n/>",description:"exportCharts embeds bar, line, pie, or doughnut charts below the data in the Excel file."})},WithExportExtraSheets={name:"Export — Extra Sheets & Summary Rows",parameters:{docs:{description:{story:"\n## Multi-Sheet Excel Export with Summary Rows\n\nUse `exportExtraSheets` to add additional worksheets to the same Excel file.\nUse `exportSummaryRows` to append totals / averages at the bottom of any sheet.\n\nEach extra sheet supports its own:\n- Data and column definitions\n- Header style (`backgroundColor`, `color`, `bold`, `fontSize`)\n- Summary rows\n- Embedded charts (bar, line, pie, doughnut)\n        "}}},render:()=>react__WEBPACK_IMPORTED_MODULE_0__.createElement(CodeExample,{title:"Export — Extra Sheets & Summary Rows",code:"<Table\n  id=\"multi-sheet-table\"\n  data={mainData}\n  columns={mainColumns}\n  exportable\n  exportFormat=\"excel\"\n  exportSheetName=\"Overview\"\n  exportHeaderStyle={{ backgroundColor: '#1e40af', color: '#ffffff' }}\n\n  // Summary rows on the main sheet\n  exportSummaryRows={[\n    {\n      label: 'Total',\n      values: { revenue: 111000, expenses: 70000 },\n      style: { fontWeight: 'bold', backgroundColor: '#f3f4f6' },\n    },\n    {\n      label: 'Average',\n      values: { revenue: 18500, expenses: 11667 },\n      style: { fontStyle: 'italic' },\n    },\n  ]}\n\n  // Additional worksheets\n  exportExtraSheets={[\n    {\n      name: 'Details',\n      data: detailData,\n      columns: [\n        { dataField: 'id', text: 'ID' },\n        { dataField: 'product', text: 'Product' },\n        { dataField: 'qty', text: 'Qty' },\n        {\n          dataField: 'amount',\n          text: 'Amount',\n          csvFormatter: (val) => `$${val.toFixed(2)}`,\n        },\n      ],\n      headerStyle: {\n        backgroundColor: '#065f46',\n        color: '#ffffff',\n        bold: true,\n        fontSize: 11,\n      },\n      summaryRows: [\n        { label: 'Total', values: { qty: 450, amount: 98200 } },\n      ],\n      charts: [\n        {\n          type: 'line',\n          title: 'Quantity Trend',\n          labels: ['Q1', 'Q2', 'Q3', 'Q4'],\n          datasets: [\n            { label: 'Qty', values: [100, 120, 110, 120], color: '#3b82f6' },\n          ],\n        },\n      ],\n    },\n    {\n      name: 'Regional Summary',\n      data: regionalData,\n      columns: [\n        { dataField: 'region', text: 'Region' },\n        { dataField: 'total', text: 'Total Sales' },\n      ],\n      headerStyle: { backgroundColor: '#7c3aed', color: '#ffffff' },\n      charts: [\n        {\n          type: 'doughnut',\n          title: 'Sales by Region',\n          labels: ['North', 'South', 'East', 'West'],\n          datasets: [\n            {\n              label: 'Sales',\n              values: [30, 25, 20, 25],\n              color: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'],\n            },\n          ],\n        },\n      ],\n    },\n  ]}\n/>",description:"exportExtraSheets adds multiple worksheets; exportSummaryRows appends totals at the bottom of any sheet."})},__namedExportsOrder=["Documentation","BasicUsage","WithSelectionActions","WithPagination","WithFilters","ServerSidePagination","WithSelectionHeaderActions","WithLoadingIndicator","WithExportStyling","WithExportCharts","WithExportExtraSheets"];Documentation.parameters={...Documentation.parameters,docs:{...Documentation.parameters?.docs,source:{originalSource:"{\n  name: 'Documentation',\n  parameters: {\n    docs: {\n      description: {\n        story: 'See the main documentation above for usage examples and API reference.'\n      }\n    }\n  },\n  render: () => null\n}",...Documentation.parameters?.docs?.source}}},BasicUsage.parameters={...BasicUsage.parameters,docs:{...BasicUsage.parameters?.docs,source:{originalSource:"{\n  name: 'Basic Usage',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Basic Table Usage\n\nThe simplest way to use the Table component.\n\n### Required Props\n- \\`id\\`: Unique identifier for the table\n- \\`data\\`: Array of data objects\n- \\`columns\\`: Array of column definitions\n\n### Optional Props\n- \\`pagination\\`: Enable pagination (default: true)\n- \\`searchable\\`: Enable global search (default: true)\n- \\`filterable\\`: Enable column filters (default: false)\n- \\`exportable\\`: Show export button (default: true)\n- \\`exportFormat\\`: \\`'excel'\\` (default) or \\`'csv'\\`\n- \\`exportHeaderStyle\\`: Export-time header color/font — see **Export — Header Style** story\n- \\`exportCharts\\`: Embed bar/line/pie/doughnut charts in the Excel file — see **Export — Embedded Charts** story\n- \\`exportExtraSheets\\`: Add extra worksheets — see **Export — Extra Sheets** story\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title=\"Basic Table Usage\" code={`import { Table, TableColumn } from 'react-restyle-components';\n\ninterface User {\n  _id: string;\n  name: string;\n  email: string;\n  age: number;\n}\n\nconst columns: TableColumn<User>[] = [\n  { dataField: 'name', text: 'Name', sort: true },\n  { dataField: 'email', text: 'Email', filter: true },\n  { dataField: 'age', text: 'Age', sort: true, filter: true },\n];\n\nconst data: User[] = [\n  { _id: '1', name: 'John Doe', email: 'john@example.com', age: 30 },\n  { _id: '2', name: 'Jane Smith', email: 'jane@example.com', age: 25 },\n];\n\n<Table \n  id=\"basic-table\" \n  data={data} \n  columns={columns}\n/>`} description=\"The simplest way to use the Table component with required props.\" />\n}",...BasicUsage.parameters?.docs?.source}}},WithSelectionActions.parameters={...WithSelectionActions.parameters,docs:{...WithSelectionActions.parameters?.docs,source:{originalSource:"{\n  name: 'With Selection Actions',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Table with Selection Actions\n\nEnable row selection and add custom action buttons/icons.\n\n### Key Features\n- \\`isSelectRow\\`: Enables checkbox selection\n- \\`isSelectSort\\`: Shows \"move selected to top\" button\n- \\`selectionActions\\`: Array of custom action icons\n- Each action receives \\`selectedRows\\` and \\`selectedKeys\\` in onClick handler\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title=\"Table with Selection Actions\" code={`import { Table } from 'react-restyle-components';\nimport { useState } from 'react';\n\nfunction MyTable() {\n  const [selectedRows, setSelectedRows] = useState<User[]>([]);\n\n  return (\n    <Table\n      id=\"table-with-actions\"\n      data={data}\n      columns={columns}\n      // Enable row selection\n      isSelectRow\n      onSelectedRow={setSelectedRows}\n      // Built-in select-sort feature (move selected to top)\n      isSelectSort\n      onSelectSort={(selectedRows, keys) => {\n        console.log('Move to top:', selectedRows);\n      }}\n      // Custom dynamic action buttons/icons\n      selectionActions={[\n        {\n          nameIcon: 'FaWhatsapp',\n          propsIcon: { size: '24', color: '#fff' },\n          onClick: (selectedRows, keys) => {\n            console.log('WhatsApp action', selectedRows);\n          },\n          tooltip: 'Send via WhatsApp',\n        },\n        {\n          nameIcon: 'FaTrash',\n          propsIcon: { size: '24', color: '#ff0000' },\n          onClick: (selectedRows, keys) => {\n            console.log('Delete action', selectedRows);\n          },\n          tooltip: 'Delete selected',\n        },\n      ]}\n    />\n  );\n}`} description=\"Enable row selection with custom action buttons/icons.\" />\n}",...WithSelectionActions.parameters?.docs?.source}}},WithPagination.parameters={...WithPagination.parameters,docs:{...WithPagination.parameters?.docs,source:{originalSource:'{\n  name: \'With Pagination\',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Table with Pagination\n\nEnable pagination with default settings.\n\n### Pagination Features\n- Default page size: 10\n- Page size changer: Shows dropdown to change items per page\n- Quick jumper: Type page number in input and click Go to jump (e.g., type 2 → Go → page 2 active)\n- Shows total count: "Showing 1-10 of 50"\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title="Table with Pagination" code={`<Table\n  id="paginated-table"\n  data={data}\n  columns={columns}\n  pagination\n/>`} description="Enable pagination with default settings. Quick jumper: type page number and click Go to jump." />\n}',...WithPagination.parameters?.docs?.source}}},WithFilters.parameters={...WithFilters.parameters,docs:{...WithFilters.parameters?.docs,source:{originalSource:'{\n  name: \'With Filters\',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Table with Filters\n\nEnable column filters and global search.\n\n### Filter Types\n- **Text Filter**: For string columns\n- **Number Filter**: For numeric columns with comparators (=, !=, >, >=, <, <=)\n- **Select Filter**: For columns with predefined options\n- **Date Filter**: For date columns with range support\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title="Table with Filters" code={`<Table\n  id="filtered-table"\n  data={data}\n  columns={columns}\n  filterable\n  searchable\n  searchPlaceholder="Search all columns..."\n/>`} description="Enable column filters and global search functionality." />\n}',...WithFilters.parameters?.docs?.source}}},ServerSidePagination.parameters={...ServerSidePagination.parameters,docs:{...ServerSidePagination.parameters?.docs,source:{originalSource:'{\n  name: \'Server-Side Pagination\',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Server-Side Pagination\n\nFor large datasets, use server-side pagination.\n\n### Key Props\n- \\`remote={true}\\`: Enables server-side mode (default)\n- \\`totalSize\\`: Total number of records on server\n- \\`onPageSizeChange\\`: Callback receives \\`(page, size)\\` - page is 1-indexed\n- \\`loading\\`: Full overlay loading (blocks interaction)\n- \\`isLoading\\`: Top-right spinner (non-blocking, table remains visible)\n\n### Auto-Detection\nIf \\`totalSize <= data.length\\`, automatically switches to client-side mode.\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title="Server-Side Pagination" code={`import { useState, useEffect } from \'react\';\n\nfunction ServerTable() {\n  const [data, setData] = useState([]);\n  const [total, setTotal] = useState(0);\n  const [isLoading, setIsLoading] = useState(false);\n\n  const fetchData = async (page: number, size: number) => {\n    setIsLoading(true);\n    try {\n      const response = await fetch(\\`/api/users?page=\\${page}&size=\\${size}\\`);\n      const result = await response.json();\n      setData(result.data);\n      setTotal(result.total);\n    } finally {\n      setIsLoading(false);\n    }\n  };\n\n  useEffect(() => {\n    fetchData(1, 10); // Initial load\n  }, []);\n\n  return (\n    <Table\n      id="server-table"\n      data={data}\n      columns={columns}\n      isLoading={isLoading}\n      pagination\n      remote\n      totalSize={total}\n      onPageSizeChange={fetchData}\n    />\n  );\n}`} description="For large datasets, fetch data from server. Use isLoading for top-right spinner or loading for full overlay." />\n}',...ServerSidePagination.parameters?.docs?.source}}},WithSelectionHeaderActions.parameters={...WithSelectionHeaderActions.parameters,docs:{...WithSelectionHeaderActions.parameters?.docs,source:{originalSource:"{\n  name: 'With Selection Header Actions',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Table with Selection Header Actions\n\nActions in the header toolbar (after Show/Hide Columns). Supports icon name or custom component.\n\n### Key Features\n- \\`selectionHeaderActions\\`: Array of actions OR single React component\n- Always visible (positioned after FilterIcon)\n- \\`nameIcon\\`: Icon from react-icons (e.g., 'FaTrash')\n- \\`customComponent\\`: Custom React element for fully custom UI\n- \\`onClick\\`: Receives selectedRows and selectedKeys\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title=\"Table with Selection Header Actions\" code={`// Array of actions (positioned after FilterIcon)\n<Table\n  id=\"header-actions-table\"\n  data={data}\n  columns={columns}\n  selectionHeaderActions={[\n    {\n      nameIcon: 'FaTrash',\n      propsIcon: { size: 18, color: '#ef4444' },\n      onClick: (rows, keys) => console.log('Delete', rows),\n      tooltip: 'Delete selected',\n    },\n    {\n      customComponent: <button>Custom</button>,\n      tooltip: 'Custom action',\n    },\n  ]}\n/>\n\n// Or single component\n<Table\n  id=\"header-actions-table\"\n  data={data}\n  columns={columns}\n  selectionHeaderActions={<button onClick={...}>My Action</button>}\n/>`} description=\"Header toolbar actions after Show/Hide Columns. Accepts array or single React component.\" />\n}",...WithSelectionHeaderActions.parameters?.docs?.source}}},WithLoadingIndicator.parameters={...WithLoadingIndicator.parameters,docs:{...WithLoadingIndicator.parameters?.docs,source:{originalSource:'{\n  name: \'With Loading Indicator\',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Table with Top-Right Loading Indicator\n\n\\`isLoading\\` shows a small LoadingAnimateSpin at the top-right corner (non-blocking).\n\n### Loading Props\n- \\`loading\\`: Full overlay (blocks interaction)\n- \\`isLoading\\`: Top-right spinner (table remains visible)\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title="Table with Loading Indicator" code={`// Top-right spinner (non-blocking)\n<Table\n  id="loading-table"\n  data={data}\n  columns={columns}\n  isLoading={isFetching}\n/>\n\n// Full overlay (blocks interaction)\n<Table\n  id="loading-table"\n  data={data}\n  columns={columns}\n  loading={loading}\n/>`} description="isLoading: top-right spinner. loading: full overlay." />\n}',...WithLoadingIndicator.parameters?.docs?.source}}},WithExportStyling.parameters={...WithExportStyling.parameters,docs:{...WithExportStyling.parameters?.docs,source:{originalSource:"{\n  name: 'Export — Header Style & Sheet Name',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Export-Time Header Styling\n\nUse \\`exportHeaderStyle\\` to control the Excel header row appearance at export time.\nThese props are **independent of runtime table styles** and only affect the exported file.\n\n### Default behaviour (no props needed)\n- Background: \\`#6b7280\\` (gray)\n- Text color: \\`#ffffff\\` (white)\n- Bold: \\`true\\`, Font size: \\`12\\`\n\n### Props\n| Prop | Type | Default |\n|---|---|---|\n| \\`exportFormat\\` | \\`'excel' \\\\| 'csv'\\` | \\`'excel'\\` |\n| \\`exportSheetName\\` | \\`string\\` | \\`'Sheet1'\\` |\n| \\`exportHeaderStyle.backgroundColor\\` | \\`string\\` | \\`'#6b7280'\\` |\n| \\`exportHeaderStyle.color\\` | \\`string\\` | \\`'#ffffff'\\` |\n| \\`exportHeaderStyle.bold\\` | \\`boolean\\` | \\`true\\` |\n| \\`exportHeaderStyle.fontSize\\` | \\`number\\` | \\`12\\` |\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title=\"Export — Header Style & Sheet Name\" code={`// Default: gray header (#6b7280) + white text — no extra props needed\n<Table\n  id=\"export-default\"\n  data={data}\n  columns={columns}\n  exportable\n  exportFormat=\"excel\"\n/>\n\n// Custom header style\n<Table\n  id=\"export-styled\"\n  data={data}\n  columns={columns}\n  exportable\n  exportFormat=\"excel\"\n  exportFileName=\"sales_report\"\n  exportSheetName=\"Sales Data\"\n  exportHeaderStyle={{\n    backgroundColor: '#1e40af', // dark blue\n    color: '#ffffff',\n    bold: true,\n    fontSize: 13,\n  }}\n/>\n\n// Green header\n<Table\n  id=\"export-green\"\n  data={data}\n  columns={columns}\n  exportable\n  exportFormat=\"excel\"\n  exportHeaderStyle={{\n    backgroundColor: '#065f46',\n    color: '#a7f3d0',\n    fontSize: 11,\n  }}\n/>`} description=\"exportHeaderStyle controls the Excel header independently of the visible table styles.\" />\n}",...WithExportStyling.parameters?.docs?.source}}},WithExportCharts.parameters={...WithExportCharts.parameters,docs:{...WithExportCharts.parameters?.docs,source:{originalSource:"{\n  name: 'Export — Embedded Charts',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Embedding Charts in Exported Excel\n\nUse \\`exportCharts\\` to embed one or more charts directly into the exported Excel sheet.\nCharts are rendered via the **browser Canvas 2D API** — no extra dependencies required.\n\n### Supported Chart Types\n- \\`'bar'\\` — vertical bar chart\n- \\`'line'\\` — line chart\n- \\`'pie'\\` — pie chart\n- \\`'doughnut'\\` — doughnut chart\n\n### Chart Positioning\nCharts are placed **below the data table** in the same sheet.\nControl placement with \\`rowOffset\\`, \\`colOffset\\`, \\`colSpan\\`, \\`rowSpan\\`.\n\n### Multiple datasets\nA single chart can carry multiple series (stacked bars, multi-line, etc.).\nFor pie / doughnut charts pass a \\`color\\` array — one colour per slice.\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title=\"Export — Embedded Charts\" code={`<Table\n  id=\"chart-export-table\"\n  data={data}\n  columns={columns}\n  exportable\n  exportFormat=\"excel\"\n  exportFileName=\"sales_report\"\n  exportSheetName=\"Sales\"\n  exportHeaderStyle={{ backgroundColor: '#1e40af', color: '#ffffff' }}\n  exportCharts={[\n    // Bar chart — multi-series\n    {\n      type: 'bar',\n      title: 'Monthly Revenue vs Expenses',\n      labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],\n      datasets: [\n        {\n          label: 'Revenue',\n          values: [12000, 19000, 15000, 22000, 18000, 25000],\n          color: '#3b82f6',\n        },\n        {\n          label: 'Expenses',\n          values: [8000, 11000, 9000, 14000, 12000, 16000],\n          color: '#ef4444',\n        },\n      ],\n      width: 700,\n      height: 400,\n      rowOffset: 2,   // rows gap below data table\n      colOffset: 0,   // anchor column (0-indexed)\n      colSpan: 10,    // how many Excel columns wide\n      rowSpan: 22,    // how many Excel rows tall\n    },\n    // Line chart\n    {\n      type: 'line',\n      title: 'Revenue Trend',\n      labels: ['Q1', 'Q2', 'Q3', 'Q4'],\n      datasets: [\n        {\n          label: 'This Year',\n          values: [45000, 56000, 53000, 67000],\n          color: '#10b981',\n        },\n        {\n          label: 'Last Year',\n          values: [38000, 44000, 47000, 59000],\n          color: '#6b7280',\n        },\n      ],\n      colOffset: 11,  // place to the right of the bar chart\n    },\n    // Pie chart — per-slice colors\n    {\n      type: 'pie',\n      title: 'Revenue by Region',\n      labels: ['North', 'South', 'East', 'West'],\n      datasets: [\n        {\n          label: 'Region',\n          values: [30, 25, 20, 25],\n          color: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'],\n        },\n      ],\n    },\n    // Doughnut chart\n    {\n      type: 'doughnut',\n      title: 'Product Mix',\n      labels: ['Product A', 'Product B', 'Product C'],\n      datasets: [\n        {\n          label: 'Mix',\n          values: [40, 35, 25],\n          color: ['#7c3aed', '#db2777', '#0891b2'],\n        },\n      ],\n    },\n  ]}\n/>`} description=\"exportCharts embeds bar, line, pie, or doughnut charts below the data in the Excel file.\" />\n}",...WithExportCharts.parameters?.docs?.source}}},WithExportExtraSheets.parameters={...WithExportExtraSheets.parameters,docs:{...WithExportExtraSheets.parameters?.docs,source:{originalSource:"{\n  name: 'Export — Extra Sheets & Summary Rows',\n  parameters: {\n    docs: {\n      description: {\n        story: `\n## Multi-Sheet Excel Export with Summary Rows\n\nUse \\`exportExtraSheets\\` to add additional worksheets to the same Excel file.\nUse \\`exportSummaryRows\\` to append totals / averages at the bottom of any sheet.\n\nEach extra sheet supports its own:\n- Data and column definitions\n- Header style (\\`backgroundColor\\`, \\`color\\`, \\`bold\\`, \\`fontSize\\`)\n- Summary rows\n- Embedded charts (bar, line, pie, doughnut)\n        `\n      }\n    }\n  },\n  render: () => <CodeExample title=\"Export — Extra Sheets & Summary Rows\" code={`<Table\n  id=\"multi-sheet-table\"\n  data={mainData}\n  columns={mainColumns}\n  exportable\n  exportFormat=\"excel\"\n  exportSheetName=\"Overview\"\n  exportHeaderStyle={{ backgroundColor: '#1e40af', color: '#ffffff' }}\n\n  // Summary rows on the main sheet\n  exportSummaryRows={[\n    {\n      label: 'Total',\n      values: { revenue: 111000, expenses: 70000 },\n      style: { fontWeight: 'bold', backgroundColor: '#f3f4f6' },\n    },\n    {\n      label: 'Average',\n      values: { revenue: 18500, expenses: 11667 },\n      style: { fontStyle: 'italic' },\n    },\n  ]}\n\n  // Additional worksheets\n  exportExtraSheets={[\n    {\n      name: 'Details',\n      data: detailData,\n      columns: [\n        { dataField: 'id', text: 'ID' },\n        { dataField: 'product', text: 'Product' },\n        { dataField: 'qty', text: 'Qty' },\n        {\n          dataField: 'amount',\n          text: 'Amount',\n          csvFormatter: (val) => \\`$\\${val.toFixed(2)}\\`,\n        },\n      ],\n      headerStyle: {\n        backgroundColor: '#065f46',\n        color: '#ffffff',\n        bold: true,\n        fontSize: 11,\n      },\n      summaryRows: [\n        { label: 'Total', values: { qty: 450, amount: 98200 } },\n      ],\n      charts: [\n        {\n          type: 'line',\n          title: 'Quantity Trend',\n          labels: ['Q1', 'Q2', 'Q3', 'Q4'],\n          datasets: [\n            { label: 'Qty', values: [100, 120, 110, 120], color: '#3b82f6' },\n          ],\n        },\n      ],\n    },\n    {\n      name: 'Regional Summary',\n      data: regionalData,\n      columns: [\n        { dataField: 'region', text: 'Region' },\n        { dataField: 'total', text: 'Total Sales' },\n      ],\n      headerStyle: { backgroundColor: '#7c3aed', color: '#ffffff' },\n      charts: [\n        {\n          type: 'doughnut',\n          title: 'Sales by Region',\n          labels: ['North', 'South', 'East', 'West'],\n          datasets: [\n            {\n              label: 'Sales',\n              values: [30, 25, 20, 25],\n              color: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'],\n            },\n          ],\n        },\n      ],\n    },\n  ]}\n/>`} description=\"exportExtraSheets adds multiple worksheets; exportSummaryRows appends totals at the bottom of any sheet.\" />\n}",...WithExportExtraSheets.parameters?.docs?.source}}}}}]);